import React, { useState, useEffect } from 'react';
import { 
  Calendar, 
  Clock, 
  Users, 
  MapPin, 
  Plus, 
  Trash2, 
  X, 
  Flame,
  Loader2
} from 'lucide-react';
import { supabase } from './lib/supabase';

export function ScheduleManager() {
  const [classes, setClasses] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Estados del formulario
  const [title, setTitle] = useState('');
  const [trainer, setTrainer] = useState('');
  const [startTime, setStartTime] = useState('');
  const [endTime, setEndTime] = useState('');
  const [maxCapacity, setMaxCapacity] = useState('20');
  const [location, setLocation] = useState('Zona Principal');
  const [intensityBadge, setIntensityBadge] = useState('Media');
  const [description, setDescription] = useState('');

  // 1. Cargar las clases desde la base de datos
  const fetchClasses = async () => {
    try {
      const today = new Date();
      today.setHours(0, 0, 0, 0); // Desde hoy a medianoche

      const { data, error } = await supabase
        .from('classes')
        .select('*')
        .gte('start_time', today.toISOString())
        .order('start_time', { ascending: true });

      if (error) throw error;
      setClasses(data || []);
    } catch (error) {
      console.error("Error cargando clases:", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchClasses();
  }, []);

  // 2. Crear una nueva clase
  const handleCreateClass = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    try {
      const { error } = await supabase.from('classes').insert([
        {
          title,
          trainer,
          start_time: new Date(startTime).toISOString(),
          end_time: new Date(endTime).toISOString(),
          max_capacity: parseInt(maxCapacity),
          location,
          intensity_badge: intensityBadge,
          description
        }
      ]);

      if (error) throw error;

      // Limpiar formulario y recargar
      setIsModalOpen(false);
      setTitle('');
      setTrainer('');
      setStartTime('');
      setEndTime('');
      setDescription('');
      fetchClasses();

    } catch (error: any) {
      alert("Error al crear la clase: " + error.message);
    } finally {
      setIsSubmitting(false);
    }
  };

  // 3. Eliminar una clase
  const handleDeleteClass = async (id: string, classTitle: string) => {
    if (window.confirm(`¿Estás seguro de que quieres cancelar la clase de ${classTitle}?`)) {
      try {
        const { error } = await supabase.from('classes').delete().eq('id', id);
        if (error) throw error;
        fetchClasses();
      } catch (error: any) {
        alert("Error al eliminar: " + error.message);
      }
    }
  };

  if (loading) {
    return (
      <div className="flex h-96 items-center justify-center">
        <Loader2 className="w-10 h-10 text-[#39FF14] animate-spin" />
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-in fade-in duration-500">

      {/* Cabecera */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-3xl font-bold text-white tracking-tight">Horarios y Clases</h1>
          <p className="text-gray-400 mt-1">Gestiona las sesiones de entrenamiento del gimnasio.</p>
        </div>
        <button 
          onClick={() => setIsModalOpen(true)}
          className="bg-[#39FF14] text-black px-6 py-3 rounded-xl font-bold hover:bg-[#2EE010] transition-colors flex items-center justify-center gap-2 shadow-[0_0_15px_rgba(57,255,20,0.2)] hover:shadow-[0_0_20px_rgba(57,255,20,0.4)]"
        >
          <Plus size={20} />
          <span>Añadir Clase</span>
        </button>
      </div>

      {/* Cuadrícula de Clases */}
      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
        {classes.map((cls) => {
          const startDate = new Date(cls.start_time);
          const endDate = new Date(cls.end_time);
          const dayName = startDate.toLocaleDateString('es-ES', { weekday: 'long' });
          const dateStr = startDate.toLocaleDateString('es-ES', { day: 'numeric', month: 'short' });
          const timeStr = `${startDate.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})} - ${endDate.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}`;

          return (
            <div key={cls.id} className="bg-[#121212] border border-[#2a2a2a] rounded-2xl p-6 group hover:border-[#39FF14]/50 transition-colors relative overflow-hidden">

              {/* Botón de eliminar (Aparece al hacer hover) */}
              <button 
                onClick={() => handleDeleteClass(cls.id, cls.title)}
                className="absolute top-4 right-4 text-gray-500 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity bg-[#1a1a1a] p-2 rounded-lg border border-[#2a2a2a] hover:border-red-500/50"
                title="Cancelar clase"
              >
                <Trash2 size={16} />
              </button>

              <div className="flex items-start justify-between mb-4">
                <div>
                  <div className="flex items-center gap-2 mb-2">
                    <span className="bg-[#39FF14]/10 text-[#39FF14] text-xs font-bold px-2 py-1 rounded-md uppercase tracking-wider">
                      {cls.intensity_badge || 'Media'}
                    </span>
                    <span className="text-gray-500 text-xs font-bold uppercase tracking-wider">
                      {dayName}, {dateStr}
                    </span>
                  </div>
                  <h3 className="text-xl font-bold text-white">{cls.title}</h3>
                </div>
              </div>

              <div className="space-y-3 mt-6">
                <div className="flex items-center gap-3 text-gray-300 text-sm">
                  <Clock size={16} className="text-[#39FF14]" />
                  <span>{timeStr}</span>
                </div>
                <div className="flex items-center gap-3 text-gray-300 text-sm">
                  <Users size={16} className="text-[#39FF14]" />
                  <span>Capacidad máxima: {cls.max_capacity} personas</span>
                </div>
                <div className="flex items-center gap-3 text-gray-300 text-sm">
                  <MapPin size={16} className="text-[#39FF14]" />
                  <span>{cls.location || 'Gimnasio'}</span>
                </div>
                <div className="flex items-center gap-3 text-gray-300 text-sm border-t border-[#2a2a2a] pt-3 mt-3">
                  <Flame size={16} className="text-[#39FF14]" />
                  <span>Coach: <span className="font-bold text-white">{cls.trainer}</span></span>
                </div>
              </div>
            </div>
          );
        })}

        {classes.length === 0 && (
          <div className="col-span-full bg-[#121212] border border-[#2a2a2a] border-dashed rounded-2xl p-12 text-center">
            <Calendar className="w-12 h-12 text-gray-600 mx-auto mb-4" />
            <h3 className="text-lg font-bold text-white mb-1">No hay clases programadas</h3>
            <p className="text-gray-400">Haz clic en "Añadir Clase" para empezar a organizar la agenda.</p>
          </div>
        )}
      </div>

      {/* Modal / Panel Flotante para Crear Clase */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-[#121212] border border-[#2a2a2a] rounded-3xl w-full max-w-2xl overflow-hidden shadow-2xl animate-in zoom-in-95 duration-200">
            <div className="flex justify-between items-center p-6 border-b border-[#2a2a2a] bg-[#1a1a1a]">
              <h2 className="text-xl font-bold text-white flex items-center gap-2">
                <Calendar className="text-[#39FF14]" />
                Programar Nueva Clase
              </h2>
              <button onClick={() => setIsModalOpen(false)} className="text-gray-400 hover:text-white transition-colors">
                <X size={24} />
              </button>
            </div>

            <form onSubmit={handleCreateClass} className="p-6 space-y-6 max-h-[70vh] overflow-y-auto">

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="text-xs text-gray-500 uppercase font-bold tracking-wider">Nombre de la clase</label>
                  <input type="text" required value={title} onChange={(e) => setTitle(e.target.value)} placeholder="Ej: CrossFit WOD" className="w-full bg-[#1a1a1a] border border-[#2a2a2a] p-3 rounded-xl mt-1.5 text-white focus:border-[#39FF14] outline-none transition-colors" />
                </div>
                <div>
                  <label className="text-xs text-gray-500 uppercase font-bold tracking-wider">Entrenador (Coach)</label>
                  <input type="text" required value={trainer} onChange={(e) => setTrainer(e.target.value)} placeholder="Ej: Marcos Silva" className="w-full bg-[#1a1a1a] border border-[#2a2a2a] p-3 rounded-xl mt-1.5 text-white focus:border-[#39FF14] outline-none transition-colors" />
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="text-xs text-gray-500 uppercase font-bold tracking-wider">Inicio</label>
                  <input type="datetime-local" required value={startTime} onChange={(e) => setStartTime(e.target.value)} className="w-full bg-[#1a1a1a] border border-[#2a2a2a] p-3 rounded-xl mt-1.5 text-white focus:border-[#39FF14] outline-none transition-colors [color-scheme:dark]" />
                </div>
                <div>
                  <label className="text-xs text-gray-500 uppercase font-bold tracking-wider">Fin</label>
                  <input type="datetime-local" required value={endTime} onChange={(e) => setEndTime(e.target.value)} className="w-full bg-[#1a1a1a] border border-[#2a2a2a] p-3 rounded-xl mt-1.5 text-white focus:border-[#39FF14] outline-none transition-colors [color-scheme:dark]" />
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div>
                  <label className="text-xs text-gray-500 uppercase font-bold tracking-wider">Capacidad Máx.</label>
                  <input type="number" required min="1" value={maxCapacity} onChange={(e) => setMaxCapacity(e.target.value)} className="w-full bg-[#1a1a1a] border border-[#2a2a2a] p-3 rounded-xl mt-1.5 text-white focus:border-[#39FF14] outline-none transition-colors" />
                </div>
                <div>
                  <label className="text-xs text-gray-500 uppercase font-bold tracking-wider">Ubicación</label>
                  <input type="text" required value={location} onChange={(e) => setLocation(e.target.value)} placeholder="Ej: Sala 1" className="w-full bg-[#1a1a1a] border border-[#2a2a2a] p-3 rounded-xl mt-1.5 text-white focus:border-[#39FF14] outline-none transition-colors" />
                </div>
                <div>
                  <label className="text-xs text-gray-500 uppercase font-bold tracking-wider">Intensidad</label>
                  <select value={intensityBadge} onChange={(e) => setIntensityBadge(e.target.value)} className="w-full bg-[#1a1a1a] border border-[#2a2a2a] p-3 rounded-xl mt-1.5 text-white focus:border-[#39FF14] outline-none transition-colors appearance-none">
                    <option value="Baja">Baja</option>
                    <option value="Media">Media</option>
                    <option value="Alta">Alta</option>
                    <option value="Extrema">Extrema</option>
                  </select>
                </div>
              </div>

              <div>
                <label className="text-xs text-gray-500 uppercase font-bold tracking-wider">Descripción (Opcional)</label>
                <textarea rows={3} value={description} onChange={(e) => setDescription(e.target.value)} placeholder="Detalles de lo que se hará en la clase..." className="w-full bg-[#1a1a1a] border border-[#2a2a2a] p-3 rounded-xl mt-1.5 text-white focus:border-[#39FF14] outline-none transition-colors resize-none" />
              </div>

              <div className="pt-4 border-t border-[#2a2a2a] flex justify-end gap-3">
                <button type="button" onClick={() => setIsModalOpen(false)} className="px-6 py-3 rounded-xl font-bold text-white hover:bg-[#1a1a1a] transition-colors">
                  Cancelar
                </button>
                <button type="submit" disabled={isSubmitting} className="bg-[#39FF14] text-black px-6 py-3 rounded-xl font-bold hover:bg-[#2EE010] transition-colors disabled:opacity-50 flex items-center gap-2">
                  {isSubmitting ? <Loader2 className="animate-spin w-5 h-5" /> : 'Guardar Clase'}
                </button>
              </div>

            </form>
          </div>
        </div>
      )}

    </div>
  );
}
